import * as assert from "assert";
type RegexLike = {
  exec(s: string): RegExpExecArray | null;
};

function isRegexLike(r: any): r is RegexLike {
  return typeof r?.exec === "function";
}
function assertRegexLike(r:any):asserts r is RegexLike{
  if(!isRegexLike(r))throw new Error("not eegex");
}
type Handler<T> = (m: RegExpExecArray, ...groups: string[]) => T;
type Pair<T> = [RegexLike, Handler<T>];
type Fallback<T> = T | ((s: string) => T);

// flatten tuple of pairs
type FlattenPairs<P extends readonly Pair<any>[]> =
    P extends [infer H, ...infer R]
        ? H extends [infer A, infer B]
            ? [A, B, ...FlattenPairs<R extends Pair<any>[] ? R : []>]
            : []
        : [];

// overloads
export function match<T, P extends readonly Pair<T>[]>(
    ...args: [...FlattenPairs<P>, Fallback<T>?]
): (s: string) => T | undefined;

export function match<T, P extends readonly Pair<T>[]>(
    s: string,
    ...args: [...FlattenPairs<P>, Fallback<T>?]
): T | undefined;

// implementation
export function match(...args: any[]): any {
    if (typeof args[0] === "string") {
        const s = args.shift();
        return match(...args)(s);
    }
    return function (s: string) {
        while (args.length >= 2) {
            let r = args.shift();
            assertRegexLike(r);

            let f = args.shift();
            assert.ok(typeof f === "function", "not function");

            let m = r.exec(s);
            if (m) {
                let a = Array.from(m);
                return f(m, ...a);
            }
        }
        if (args.length === 1) {
            let f = args.shift();
            if (typeof f === "function") return f(s);
            return f;
        }
    };
}
